#include <stdio.h>

int main() {
    int T, X;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &X);
        if (X > 65) {
            printf("Overload\n");
        } else if (X < 35) {
            printf("Underload\n");
        } else {
            printf("Normal\n");
        }
    }
    return 0;
}

